mapper.select:
SELECT fp.*, u.nickname as author_name, u.avatar as author_avatar FROM forum_post fp LEFT JOIN sys_user u ON fp.user_id = u.id WHERE fp.status = 1
AND fp.post_type = #{postType}
ORDER BY fp.is_top DESC, fp.create_time DESC

SELECT fp.*, u.nickname as author_name, u.avatar as author_avatar FROM forum_post fp LEFT JOIN sys_user u ON fp.user_id = u.id WHERE fp.status = 1
AND fp.post_type = #{postType}
ORDER BY fp.is_top DESC, fp.like_count DESC, fp.create_time DESC

SELECT fp.*, u.nickname as author_name, u.avatar as author_avatar FROM forum_post fp LEFT JOIN sys_user u ON fp.user_id = u.id WHERE fp.status = 1
AND fp.post_type = #{postType}
ORDER BY fp.is_top DESC, fp.comment_count DESC, fp.create_time DESC

SELECT fp.*, u.nickname as author_name, u.avatar as author_avatar FROM forum_post fp LEFT JOIN sys_user u ON fp.user_id = u.id WHERE fp.status = 1
AND fp.post_type = #{postType}
AND (fp.title LIKE CONCAT('%', #{keyword}, '%') OR fp.content LIKE CONCAT('%', #{keyword}, '%')) ORDER BY fp.is_featured DESC, fp.create_time DESC
